package com.chaobo.scm.supplier.application.item;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.infrastructure.persistence.item.SupplierItemHistoryQueryMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;import java.time.*;import java.util.*;
@Service public class SupplierItemHistoryQueryApplicationService {private final SupplierItemReadModelPort items;private final SupplierItemHistoryQueryMapper mapper;public SupplierItemHistoryQueryApplicationService(SupplierItemReadModelPort items,SupplierItemHistoryQueryMapper mapper){this.items=items;this.mapper=mapper;}@Transactional(readOnly=true)public List<Condition> conditions(long itemId,Long scope){var item=items.detail(itemId).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"供应商商品不存在"));check(scope,item.supplierId());return mapper.conditions(itemId).stream().map(v->new Condition(v.id(),v.moq(),v.mpq(),v.days(),v.unit(),v.from(),v.to(),v.version(),v.type(),v.operator(),v.changedAt())).toList();}@Transactional(readOnly=true)public List<Price> prices(long supplierId,String sku,Long scope){check(scope,supplierId);return mapper.prices(supplierId,sku).stream().map(v->new Price(v.id(),v.agreement(),v.currency(),v.price(),v.tax(),v.from(),v.to(),v.contractId(),v.quoteId(),v.version(),v.createdAt())).toList();}private static void check(Long scope,long supplierId){if(scope!=null&&scope!=supplierId)throw new BusinessException(ErrorCode.NOT_FOUND,"供应商商品不存在");}public record Condition(long id,BigDecimal moq,BigDecimal mpq,int leadTimeDays,String purchaseUnit,LocalDate effectiveFrom,LocalDate effectiveTo,int version,String changeType,long changedBy,OffsetDateTime changedAt){}public record Price(long id,String agreementRef,String currency,BigDecimal unitPrice,BigDecimal taxRate,LocalDate effectiveFrom,LocalDate effectiveTo,long contractId,long quoteId,int version,OffsetDateTime createdAt){}}
